import org.springframework.ai.mcp.SyncMcpToolCallbackProvider;
import io.modelcontextprotocol.client.McpClient;
import io.modelcontextprotocol.client.transport.HttpClientStreamableHttpTransport;
import io.modelcontextprotocol.spec.McpSchema;

var transport = HttpClientStreamableHttpTransport.builder("http://localhost:8080")
        .endpoint("/mcp")
        .build();

var mcpClient = McpClient.sync(transport)
        .clientInfo(new McpSchema.Implementation("dice-mcp-client", "1.0.0"))
        .build();

mcpClient.initialize();

// Step 2: Discover available tools from the MCP Server
var toolsResult = mcpClient.listTools();
var toolNames = toolsResult.tools().stream().map(McpSchema.Tool::name).toList();
log.info("Available tools: {}", toolNames);

// Step 3: Bridge MCP tools into Spring AI ToolCallbacks
var mcpToolProvider = SyncMcpToolCallbackProvider.builder()
        .mcpClients(mcpClient)
        .build();
var mcpTools = mcpToolProvider.getToolCallbacks();

System.setProperty("server.port", "8000");
System.setProperty("server.servlet.context-path", "/a2a");
System.setProperty("spring.application.name", "rules-agent");
System.setProperty("spring.ai.a2a.server.enabled", "true");

@Bean
AgentExecutor agentExecutor(BedrockProxyChatModel chatModel, RulesTools rulesTools) {
    var chatClient = ChatClient.builder(chatModel)
            .defaultSystem(SYSTEM_PROMPT)
            .defaultTools(rulesTools)
            .build();

    return new DefaultAgentExecutor(chatClient, (chat, requestContext) -> {
        String userMessage = DefaultAgentExecutor.extractTextFromMessage(requestContext.getMessage());
        return chat.prompt().user(userMessage).call().content();
    });
}

System.setProperty("server.port", "8001");
System.setProperty("server.servlet.context-path", "/a2a");
System.setProperty("spring.application.name", "character-agent");
System.setProperty("spring.ai.a2a.server.enabled", "true");

@Bean
AgentExecutor agentExecutor(BedrockProxyChatModel chatModel, CharacterTools characterTools) {
    var chatClient = ChatClient.builder(chatModel)
            .defaultSystem(SYSTEM_PROMPT)
            .defaultTools(characterTools)
            .build();

    return new DefaultAgentExecutor(chatClient, (chat, requestContext) -> {
        String userMessage = DefaultAgentExecutor.extractTextFromMessage(requestContext.getMessage());
        return chat.prompt().user(userMessage).call().content();
    });
}

@Bean
ToolCallback[] mcpTools() {
    try {
        var transport = HttpClientStreamableHttpTransport.builder("http://localhost:8080")
                .endpoint("/mcp")
                .build();

        var client = McpClient.sync(transport)
                .clientInfo(new McpSchema.Implementation("gamemaster-mcp-client", "1.0.0"))
                .build();

        client.initialize();

        var tools = client.listTools().tools().stream().map(McpSchema.Tool::name).toList();
        log.info("MCP tools discovered: {}", tools);

        return SyncMcpToolCallbackProvider.builder()
                .mcpClients(client)
                .build()
                .getToolCallbacks();
    } catch (Exception e) {
        log.warn("MCP Dice Server not available at http://localhost:8080/mcp \u2014 dice rolling disabled");
        log.warn("Start it with: cd ../chapter4 && jbang DiceRollMcpServer.java");
        return new ToolCallback[0];
    }
}

@Bean
ChatClient chatClient(BedrockProxyChatModel chatModel,
                       GameMasterService remoteAgent) {

    String systemPrompt = SYSTEM_PROMPT.formatted(remoteAgent.getAgentDescriptions());

    log.info("Initializing routing ChatClient with agents: {}", remoteAgent.getAgentNames());

    return ChatClient.builder(chatModel)
            .defaultSystem(systemPrompt)
            .build();
}
